    setDrivers(driverOptions); setVehicles(vehicleOptions); setSchedules(data.schedules.map((schedule) => { const driver = schedule.driver_id ? driverMap.get(schedule.driver_id) : undefined; const vehicle = schedule.vehicle_id ? vehicleMap.get(schedule.vehicle_id) : undefined; const shiftType = normalizeShift(schedule.shift_type); return { scheduleId: schedule.schedule_id, driverId: schedule.driver_id ?? "", vehicleId: schedule.vehicle_id ?? "", driverName: driver?.name ?? "Unnamed driver", driverEmail: driver?.email ?? "", vehicleName: vehicleName(vehicle), vehicleLabel: vehicle ? vehicleLabel(vehicle) : "No vehicle assigned", vehiclePlate: vehicle?.license_plate ?? "", date: schedule.shift_date ?? (schedule.start_time ? dateOnly(new Date(schedule.start_time)) : ""), shiftType, shiftName: schedule.shift_name ?? shiftOptions.find((item) => item.value === shiftType)?.label ?? "Shift", startTime: schedule.start_time ?? "", endTime: schedule.end_time ?? "", status: normalizeStatus(schedule.status), notes: schedule.notes ?? "" }; }));
