  const totalPages = Math.max(1, Math.ceil(calendarDrivers.length / DEFAULT_PAGE_SIZE)); const activePage = Math.min(currentPage, totalPages); const pageDrivers = calendarDrivers.slice((activePage - 1) * DEFAULT_PAGE_SIZE, activePage * DEFAULT_PAGE_SIZE);
  const today = dateOnly(now); const activeToday = schedules.filter((schedule) => schedule.date === today && displayStatus(schedule, conflictMap.get(schedule.scheduleId) ?? []) === "scheduled").length; const availableToday = drivers.filter((driver) => driver.isActive && driver.availability !== "unavailable").length; const selectedMonthKey = `${selectedYear}-${String(selectedMonth + 1).padStart(2, "0")}`; const selectedWeekDays = weekDays(dateOnly(new Date(selectedYear, selectedMonth, selectedDay))); const selectedWeekDateSet = new Set(selectedWeekDays.map(dateOnly)); const monthlySchedules = filtered.filter((schedule) => schedule.date.startsWith(selectedMonthKey)); const weeklySchedules = filtered.filter((schedule) => selectedWeekDateSet.has(schedule.date)); const totalHours = monthlySchedules.reduce((sum, schedule) => sum + scheduleDurationHours({ driver_id: schedule.driverId, vehicle_id: schedule.vehicleId, start_time: schedule.startTime, end_time: schedule.endTime, status: schedule.status }), 0); const weeklyHours = weeklySchedules.reduce((sum, schedule) => sum + scheduleDurationHours({ driver_id: schedule.driverId, vehicle_id: schedule.vehicleId, start_time: schedule.startTime, end_time: schedule.endTime, status: schedule.status }), 0); const conflictCount = Array.from(conflictMap.values()).filter((reasons) => reasons.length).length; const utilization = drivers.length ? Math.round((weeklyHours / (drivers.length * 40)) * 100) : null;

