    const baseSchedules = schedules.filter((item) => item.scheduleId !== editingSchedule?.scheduleId); const candidates: ScheduleRecord[] = [];
    for (const payload of payloads) { const candidate: ScheduleRecord = { scheduleId: editingSchedule?.scheduleId ?? `new-${payload.shift_date}`, driverId: payload.driver_id, vehicleId: payload.vehicle_id ?? "", driverName: driver.name, driverEmail: driver.email, vehicleName: vehicle?.name ?? "No vehicle", vehicleLabel: vehicle?.label ?? "No vehicle assigned", vehiclePlate: vehicle?.licensePlate ?? "", date: payload.shift_date, shiftType: payload.shift_type, shiftName: payload.shift_name, startTime: payload.start_time, endTime: payload.end_time, status: payload.status, notes: payload.notes ?? "" }; const reasons = conflictReasons(candidate, [...baseSchedules, ...candidates]); if (reasons.length) { setErrorMessage(`${payload.shift_date}: ${reasons.join(" ")}`); setIsSaving(false); return; } candidates.push(candidate); }
